sql:
SELECT site_id, COUNT(*) AS inspection_count
FROM inspections
GROUP BY site_id;

SELECT site_id, SUM(quantity) AS total_waste
FROM hazardous_waste
GROUP BY site_id;

SELECT COUNT(DISTINCT site_id) AS active_site_count
FROM permits
WHERE permit_status = 'active';

SELECT name
FROM sites
ORDER BY site_id;

SELECT DISTINCT s.name
FROM sites s
JOIN (
    SELECT DISTINCT site_id
    FROM enforcement_actions
) ea ON s.site_id = ea.site_id
JOIN (
    SELECT DISTINCT site_id
    FROM inspections
) i ON s.site_id = i.site_id;

external_knowledge:
; Active sites refer to those currently in operation and not closed or proposed; 
; Hazardous waste quantity is a measure of the amount of waste at each site, which is a critical factor in determining environmental impact;
; The total number of inspections is an indicator of the site's compliance with safety regulations.

